INSERT INTO public.photos VALUES (25572, 'El Pilar 1908', 'Imagen estereoscâ”œâ”‚pica capturada desde el puente de Piedra y centrada en el templo del Pilar. A la izquierda, el colegio de los Infantes del Pilar y jardines de la casa de los marqueses de Ayerbe. A la derecha y hacia el fondo, la iglesia de San Juan de los Panetes.', 1908, 1908, 1908, 'Anos 1900', 'CASCO HISTâ”œÃ´RICO', 41.65702600, -0.87800500, '0101000020E6100000F12E17F19D18ECBF944F8F6D19D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51425415660.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51425415660.webp', 'https://www.flickr.com/photos/zaragozaantigua/51425415660/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (26057, 'Râ”œÂ¡o Ebro 1938', 'Imagen capturada desde un aeroplano Heinkel 45-F 2 de la Legiâ”œâ”‚n Câ”œâ”‚ndor en funciones de reconocimiento sobrevolando la ribera del râ”œÂ¡o Ebro sobre el Arrabal. En primer tâ”œÂ®rmino, la arboleda de Macanaz y la casilla del enlace ferroviario. Centra la escena la tradicional fachada edilicia de la margen derecha desde el puente de Piedra hasta la Puerta del Fin, con el templo del Pilar en medio.', 1938, 1938, 1938, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65768300, -0.87701700, '0101000020E61000002D27A1F48510ECBF4D11E0F42ED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33386230721.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33386230721.webp', 'https://www.flickr.com/photos/zaragozaantigua/33386230721/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (26074, 'Râ”œÂ¡o Ebro c. 1900', 'Imagen capturada en la margen izquierda del râ”œÂ¡o Ebro, entre el puente de Piedra y el comienzo de la alameda de Macanaz, y centrada en el templo del Pilar con su torre de Santiago. A la izquierda, la casa de los marqueses de Ayerbe y la de los Infantes del Pilar, por la que asoma una de las câ”œâ•‘pulas del pasaje de la Industria y el Comercio. A la derecha, la torre de la iglesia de San Pablo Apâ”œâ”‚stol, el torreâ”œâ”‚n de la Zuda y la torre y cupulilla de la iglesia de San Juan de los Panetes, tras la que se abrâ”œÂ¡a la Puerta de San Ildefonso.', 1900, 1900, 1900, 'Anos 1900', 'CASCO HISTâ”œÃ´RICO', 41.65728200, -0.87825100, '0101000020E6100000CBBC55D7A11AECBFEF1F0BD121D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51666365183.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51666365183.webp', 'https://www.flickr.com/photos/zaragozaantigua/51666365183/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20939, 'El Pilar 1778', 'Dibujo realizado por el arquitecto Fernando Martâ”œÂ¡nez Corcâ”œÂ¡n de los volâ”œâ•‘menes exteriores proyectados por Ventura Rodrâ”œÂ¡guez, y en buena parte no realizados, para la iglesia del Pilar, en este caso centrada en la fachada recayente a la ribera del Ebro. Destaca el ingreso principal establecido en el centro de la fachada, la soledad de la câ”œâ•‘pula del coro, a la derecha, y la altura y remate de las torres de las esquinas. Flanquean al templo, a la izquierda, la Casa de los Infantes, cercana a las Casas de la Ciudad; y a la derecha, los almacenes prâ”œâ”‚ximos a la iglesia de San Juan de Malta o de los Panetes.', 1778, 1778, 1778, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65679800, -0.87852000, '0101000020E6100000B0389CF9D51CECBF030AF5F411D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/45767943864.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/45767943864.webp', 'https://www.flickr.com/photos/zaragozaantigua/45767943864/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20955, 'Zaragoza 1806', '"Nuestra Seâ”œâ–’ora del Pilar en Zarragossa", dibujo de Lejeune grabado por Daudet, 1806. La ciudad de Zaragoza, con el Puente de Piedra sobre el Ebro, la Seo y el Pilar. Aparece representada la iglesia de San Juan del Puente, al inicio de â”œÂ®ste. Y bajo la arcada central puede verse el torreâ”œâ”‚n de Monserrate, que se levantaba sobre el estribo derecho del Puente de Tablas. Fuente: â”œÃ¼lbum grâ”œÃ­fico de Zaragoza, 1985', 1806, 1806, 1806, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65888300, -0.87877900, '0101000020E6100000B22B2D23F51EECBFF871344756D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15262551954.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15262551954.webp', 'https://www.flickr.com/photos/zaragozaantigua/15262551954/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20989, 'Alegorâ”œÂ¡a de Zaragoza 1818', 'â”œÃ´leo sobre lienzo con el boceto del telâ”œâ”‚n de boca del Teatro Principal de Zaragoza. Cristâ”œâ”‚bal Garrigo, 1818. Alegorâ”œÂ¡a clâ”œÃ­sica en la que Zaragoza, vestida como Palas, es conducida al Parnaso por Apolo y Talâ”œÂ¡a. A la derecha, la fuente Castalia y las tres musas Calâ”œÂ¡ope, Erato y Polimnia, que entregan sus aguas a un viejo, el râ”œÂ¡o Ebro. En el centro, Melpâ”œâ”‚mene y tres de sus geniecillos; Euterpe y Terpsicore. Abajo a la izquierda, los delitos y los vicios son lanzados al Averno. Mâ”œÃ­s arriba, Clâ”œÂ¡o, el Tiempo y Urania. Arriba a la derecha, Pegaso vuela junto al templo de la Fama en la cima del monte Parnaso. Al fondo a la izquierda, el templo del Pilar. Arriba, dos angelotes sostienen el escudo nobiliario de la marquesa de Lazâ”œÃ­n, a la que estâ”œÃ­ dedicada la obra. Fuente: Actas del curso "Arte del siglo XIX", IFC, 2013.', 1818, 1818, 1818, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65687500, -0.87856200, '0101000020E61000006B44300E2E1DECBFAE47E17A14D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24697071697.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24697071697.webp', 'https://www.flickr.com/photos/zaragozaantigua/24697071697/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21035, 'El Pilar 1869', 'Vista del Pilar a orillas del Ebro, con la câ”œâ•‘pula central a punto de ser terminada. Fuente: Mariano Jâ”œâ•‘dez y Ortiz. Colecciâ”œâ”‚n Antonio Arguas Perdiguer. Libro Primeros tiempos de la fotografâ”œÂ¡a en Zaragoza.', 1869, 1869, 1869, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65684700, -0.87854300, '0101000020E6100000BB26A435061DECBFE4BCFF8F13D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27968578614.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27968578614.webp', 'https://www.flickr.com/photos/zaragozaantigua/27968578614/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21039, 'El Pilar c.1860', 'Recreaciâ”œâ”‚n del templo del Pilar con el râ”œÂ¡o Ebro en primer plano, en una estampa piadosa de la casa Bonasse Lebel de Parâ”œÂ¡s. La inacabada torre de Santiago, con la ayuda de las palmeras, deviene en minarete. Fuente: www.delcampe.net', 1860, 1860, 1860, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65685400, -0.87850000, '0101000020E6100000E9263108AC1CECBF971FB8CA13D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36538628395.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36538628395.webp', 'https://www.flickr.com/photos/zaragozaantigua/36538628395/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21041, 'El Pilar 1869', '"Saragossa Cathedral, from the Ebro". Imagen del templo del Pilar capturada desde la margen izquierda, entre la vâ”œÂ¡a del empalme de las lâ”œÂ¡neas fâ”œÂ®rreas de Barcelona y Pamplona y la ribera del râ”œÂ¡o Ebro. El angular fotogrâ”œÃ­fico nos ofrece una sobresaliente panorâ”œÃ­mica de este tramo de la fachada ribereâ”œâ–’a de la margen derecha, desde la casa de los marqueses de Ayerbe y el Colegio de los Infantes hasta la puerta del Fin y la iglesia de San Juan de los Panetes. En el Pilar destacan los andamios de obra en torno a la gran câ”œâ•‘pula central, en construcciâ”œâ”‚n desde 1866 con proyecto de los arquitectos Juan Antonio Atienza y Josâ”œÂ® Yarza y Miâ”œâ–’ana, que serâ”œÃ­ terminada en agosto de ese aâ”œâ–’o. A la derecha, la inacabada y original â”œâ•‘nica torre del termplo, denominada de Santiago, con su caracterâ”œÂ¡stico y provisional tejadillo a dos aguas. Sobre el Ebro, un par de barcas y el monumental reflejo de la iglesia metropolitana. En la margen derecha, la abrupta pendiente ribereâ”œâ–’a producto del depâ”œâ”‚sito artificial de materiales acumulado para ganar terreno al râ”œÂ¡o y hacer posible la ambiciosa ampliaciâ”œâ”‚n del Pilar emprendida en 1681. Fuente visual: Francis Frith, en J. Paul Getty Museum', 1869, 1869, 1869, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65679800, -0.87852000, '0101000020E6100000B0389CF9D51CECBF030AF5F411D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/45382125452.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/45382125452.webp', 'https://www.flickr.com/photos/zaragozaantigua/45382125452/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21087, 'El Pilar 1872', 'Dibujo del entorno de la plaza del Pilar, bastante mâ”œÃ­s despejado de la realidad del momento, donde destaca la nueva figura de la iglesia metropolitana de Nuestra Seâ”œâ–’ora del Pilar tras la culminaciâ”œâ”‚n de las obras de la gran câ”œâ•‘pula central y las câ”œâ•‘pulas laterales. El entusiasmo del dibujante por la magnificencia del resultado le ha llevado a aâ”œâ–’adir, por el mismo precio, un ilusorio tercer cuerpo extra a la câ”œâ•‘pula central. A su lado, la inacabada torre de Santiago parece mâ”œÃ­s demediada que nunca. Al fondo, a la izquierda, el complejo de San Juan de los Panetes. Fuente: dibujo de Ferrer, en "La vuelta por Espaâ”œâ–’a : viaje histâ”œâ”‚rico, geogrâ”œÃ­fico, cientâ”œÂ¡fico recreativo y pintoresco : historia popular de Espaâ”œâ–’a en su parte geogrâ”œÃ­fica, civil y polâ”œÂ¡tica... / escrita en virtud de los datos adquiridos en las mismas localidades por una sociedad de literatos" (tomo I), Barcelona, 1872.', 1872, 1872, 1872, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65685400, -0.87850000, '0101000020E6100000E9263108AC1CECBF971FB8CA13D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34077894373.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34077894373.webp', 'https://www.flickr.com/photos/zaragozaantigua/34077894373/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21173, 'Conservas Salvadâ”œâ”‚ 1897', 'Etiqueta para recipiente de conserva de tomate al natural de la fâ”œÃ­brica de conservas Francisco Salvadâ”œâ”‚, sita en la calle de las Armas 14. El dibujo incluye un aspecto del Pilar. Fuente: www.todocoleccion.net', 1897, 1897, 1897, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65681400, -0.87852200, '0101000020E6100000DE205A2BDA1CECBF08C72C7B12D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31088263441.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31088263441.webp', 'https://www.flickr.com/photos/zaragozaantigua/31088263441/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
