INSERT INTO public.photos VALUES (21324, 'Vista 1908', 'Imagen capturada desde la altura de la torre de Santiago del templo metropolitano del Pilar, con una vista orientada hacia el râ”œÂ¡o Ebro y la zona ribereâ”œâ–’a comprendida entre los puentes de Piedra y de Hierro. En primer tâ”œÂ®rmino y sobre la câ”œâ•‘pula central, detalle de la decoraciâ”œâ”‚n e iluminaciâ”œâ”‚n especial diseâ”œâ–’adas por la casa Kribben de Madrid, instaladas en el Pilar con motivo de las celebraciones del centenario de los asedios de 1908-09 y la Exposiciâ”œâ”‚n Hispano-Francesa de 1908. A la derecha, la reciente torre de Nuestra Seâ”œâ–’ora del Pilar y la barroca de la Seo.', 1908, 1908, 1908, 'Anos 1900', 'CASCO HISTâ”œÃ´RICO', 41.65676100, -0.87846600, '0101000020E6100000E4BB94BA641CECBFE62494BE10D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48981579242.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48981579242.webp', 'https://www.flickr.com/photos/zaragozaantigua/48981579242/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
