INSERT INTO public.photos VALUES (21388, 'El Pilar 1915', 'Foto L. Cepero. Desde la basilical torre de Nâ”¬Â¬ Sâ”¬Â¬ del Pilar, bajo una mortecina luz, el râ”œÂ¡o Ebro y sus mâ”œÃ­rgenes, la derecha edilicia, y la izquierda, despejada, en una visual irrepetible â”¬Â½Ã”Ã‡Âªporque las estirpes condenadas a cien aâ”œâ–’os de soledad no tenâ”œÂ¡an una segunda oportunidad sobre la tierraâ”¬â•—. Fuente: La Esfera, 23 de octubre de 1915.', 1915, 1915, 1915, 'Anos 10', 'CASCO HISTâ”œÃ´RICO', 41.65827400, -0.87892900, '0101000020E61000000531D0B52F20ECBF4FE78A5242D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19869940878.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19869940878.webp', 'https://www.flickr.com/photos/zaragozaantigua/19869940878/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21391, 'El Pilar 1918', 'Foto: Kurt Hielscher. Vista de la basâ”œÂ¡lica del Pilar de Zaragoza. Al fondo, la iglesia de San Juan de los Panetes y la chimenea de la Alcoholera Agrâ”œÂ¡cola del Pilar, junto al Ayuntamiento en la plaza de Santo Domingo. Fuente: www.facebook.com/photo.php?fbid=894087094001697&set=g...', 1918, 1918, 1918, 'Anos 10', 'CASCO HISTâ”œÃ´RICO', 41.65687900, -0.87847900, '0101000020E61000000C21E7FD7F1CECBFF0366F9C14D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21150450192.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21150450192.webp', 'https://www.flickr.com/photos/zaragozaantigua/21150450192/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21489, 'Vista del Pilar 1925', 'Miguel Faci Abad. 1920-1925. "Zaragoza. Basâ”œÂ¡lica del Pilar". Desde la azotea del Casino Mercantâ”œÂ¡l, un vistazo hacia la ribera se topa con el Pilar, ademâ”œÃ­s de con todo el caserâ”œÂ¡o urbano del momento que es fâ”œÂ¡sicamente posible ver, tanto a este lado del Ebro, como en el lado del Arrabal. A este lado, a la izquierda inmediata, la pequeâ”œâ–’a trinchera de la calle Blasâ”œâ”‚n Aragonâ”œÂ®s y su desembocadura en la plaza de Sas. La cantidad de solanares (terrazas o galerâ”œÂ¡as orientadas al sol) es impresionante, y hace que el relieve de los tejados sea abrupto, como de una sierra urbana. Suaviza algo este paisaje los bulbosos remates del edificio del burguâ”œÂ®s Pasaje de El Ciclâ”œâ”‚n, ya en la plaza del Pilar. Seguimos en esta ribera con los airosos remates de la Lonja, y un poco antes, la torre que se eleva de la tardo-barroca iglesia de la Exaltaciâ”œâ”‚n de la Santa Cruz. Al otro lado del râ”œÂ¡o, a la derecha, visual de las torrecillas de Nâ”¬Â¬ Sâ”¬Â¬ de Altabâ”œÃ­s, y el par de chimeneas de la Azucarera de Aragâ”œâ”‚n, o del Arrabal. Fuente visual: "Miguel y Gabriel Faci. Fotâ”œâ”‚grafos fundadores de la Real Sociedad Fotogrâ”œÃ­fica de Zaragoza.", Alfredo Romero y Ricardo Centellas, Diputaciâ”œâ”‚n Provincial de Zaragoza, 1999.', 1925, 1925, 1925, 'Anos 20', 'CASCO HISTâ”œÃ´RICO', 41.65682700, -0.87847600, '0101000020E6100000C8444AB3791CECBF9D103AE812D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15149063954.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15149063954.webp', 'https://www.flickr.com/photos/zaragozaantigua/15149063954/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21504, 'Vista desde el Pilar 1925', 'Miguel Faci Abad. 1920-1925. "Zaragoza. Vista del Arrabal desde la torre vieja del Pilar". Le hemos tenido que dar la vuelta (horizontalmente) a la imagen para rescatarla del caos y la desorientaciâ”œâ”‚n en que estaba sumida, porque el tâ”œÂ¡tulo dice una cosa, y luego la vista era otra. Ahora se ven las cosas como si fuera Zaragoza, el puente de las Piedras y el Ebro, no Leningrado, el puente Azul y el Gran Neva. La imagen, asâ”œÂ¡, estâ”œÃ­ capturada desde la torre de Santiago del Pilar. El puente de las Piedras, entre la gran câ”œâ•‘pula central, y la segunda câ”œâ•‘pula menor de la fachada al Ebro. Justo detrâ”œÃ­s, el antiguo convento de San Lâ”œÃ­zaro, en el cuartel del mismo nombre. A la izquierda, tras la arboleda de Macanaz, el Arrabal con varios elementos referenciales: la cubierta a dos vertientes de la Estaciâ”œâ”‚n del Norte; las dos torrecillas flanqueando la Iglesia de Nuestra Seâ”œâ–’ora de Altabâ”œÃ­s, junto al convento de terciarias franciscanas de Altabâ”œÃ­s; y las dos chimeneas de la Azucarera de Aragâ”œâ”‚n, o del Arrabal. La gran diagonal arbolada de la carretera de Cataluâ”œâ–’a conduce hasta el Gâ”œÃ­llego. Fuente visual: "Miguel y Gabriel Faci. Fotâ”œâ”‚grafos fundadores de la Real Sociedad Fotogrâ”œÃ­fica de Zaragoza.", Alfredo Romero y Ricardo Centellas, Diputaciâ”œâ”‚n Provincial de Zaragoza, 1999.', 1925, 1925, 1925, 'Anos 20', 'CASCO HISTâ”œÃ´RICO', 41.65688100, -0.87912000, '0101000020E6100000FD4D2844C021ECBF902E36AD14D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15578579599.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15578579599.webp', 'https://www.flickr.com/photos/zaragozaantigua/15578579599/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21517, 'El Pilar c.1920', 'Casino Mercantil y Agrâ”œÂ¡cola. c.1920. Tras la remodelaciâ”œâ”‚n del antiguo palacio-casa de Juan de Coloma segâ”œâ•‘n proyecto de Francisco Albiâ”œâ–’ana, la directiva del Casino Mercantil y Agrâ”œÂ¡cola decidiâ”œâ”‚ iluminar los interiores de su nueva sede con imâ”œÃ­genes alegâ”œâ”‚ricas segâ”œâ•‘n la moda Regionalista y Costumbrista del momento, acudiendo a los artistas locales mâ”œÃ­s propicios. La basâ”œÂ¡lica concatedral no podâ”œÂ¡a faltar en la nâ”œâ”‚mina de asuntos iconâ”œâ”‚dulos. En la imagen, una sublimaciâ”œâ”‚n del Pilar despojada de referencias espaciales concretas, al menos en el territorio de las tres dimensiones fâ”œÂ¡sicas estâ”œÃ­ndares. Los tonos dorados de un atardecer resplandeciente difuminan los contornos del râ”œÂ¡o, la ribera, el puente. La ciudad parece mâ”œÃ­s ubâ”œÂ®rrima que de costumbre.', 1920, 1920, 1920, 'Anos 20', 'CASCO HISTâ”œÃ´RICO', 41.65682700, -0.87847600, '0101000020E6100000C8444AB3791CECBF9D103AE812D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15890488675.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15890488675.webp', 'https://www.flickr.com/photos/zaragozaantigua/15890488675/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21539, 'Arboleda de Macanaz 1929', 'La arboleda de Macanaz de Zaragoza, Luicien Roisin, 1929. Niâ”œâ–’os en la arboleda de Macanaz, en la Margen Izquierda del Ebro. Al fondo, el puente de Piedra. Fuente: "Zaragoza, aâ”œâ–’os veinte. 81 fotografâ”œÂ¡as de Roisin (1925-1931)", Instituciâ”œâ”‚n Fernando el Catâ”œâ”‚lico, 2014.', 1929, 1929, 1929, 'Anos 20', 'CASCO HISTâ”œÃ´RICO', 41.65894200, -0.87963500, '0101000020E6100000BC57AD4CF825ECBFFDFA213658D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19904267059.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19904267059.webp', 'https://www.flickr.com/photos/zaragozaantigua/19904267059/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
