INSERT INTO public.photos VALUES (21796, 'Cimientos del Pilar ca. 1930', '"Muralla en la pilastra nâ”œâ•‘mero 10. Templo del Pilar". Aspecto del subsuelo de la basâ”œÂ¡lica, bajo un emplazamiento cercano a la puerta oeste de la ribera. En 1923, Teodoro Râ”œÂ¡os proyectâ”œâ”‚ unas obras de mantenimiento del templo que se prolongaron hasta 1940. Incluyeron refuerzos de hormigâ”œâ”‚n, como los que se observan aquâ”œÂ¡ sobre la muralla romana, y que comenzaron a aplicarse en 1930. Fuente: Archivo Mora, AMZ. ES. 50297. AM 04.01.01.01 Sobre 07430.', 1930, 1930, 1930, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65711900, -0.87866100, '0101000020E610000037A968ACFD1DECBF454AB3791CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25325501029.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25325501029.webp', 'https://www.flickr.com/photos/zaragozaantigua/25325501029/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21879, 'Pl. del Pilar 1936', 'Imagen capturada en la plaza del Pilar y centrada en el "Altar de los Caâ”œÂ¡dos" instalado de forma efâ”œÂ¡mera ante la fachada sur de la basâ”œÂ¡lica del Pilar, con motivo de los actos organizados en el tercer aniversario de la fundaciâ”œâ”‚n del partido polâ”œÂ¡tico Falange Espaâ”œâ–’ola en el Teatro de la Comedia de Madrid (29 de octubre de 1933). Tras una misas matutinas en homenaje a los falangistas muertos, por este espacio procesionaron los falangistas locales acompaâ”œâ–’ados por varios miles llegados de Logroâ”œâ–’o. Este fue un destacado acto de reafirmaciâ”œâ”‚n de la "Patria tan escarnecida por el marxismo y tan defendida con tesâ”œâ”‚n por estos hombres de las flechas y la camisa azul", celebrado en la Zaragoza levantada en armas contra la democracia a mediados de julio de ese aâ”œâ–’o. El exento conjunto simbâ”œâ”‚lico de la imagen fue instalado en el centro de la soleada fachada sur del templo del Pilar, entre las dos zonas ajardinadas y arboladas que entonces definâ”œÂ¡an el espacio de la recoleta plaza homâ”œâ”‚nima, confrontando directamente con el desemboque de la calle de Alfonso I. Presiden un enorme yugo y flechas como sâ”œÂ¡mbolos del partido polâ”œÂ¡tico Falange Espaâ”œâ–’ola, y la leyenda "Presente" como muestra del recuerdo al "Ausente" Josâ”œÂ® Antonio Primo de Rivera.. En la dâ”œÂ®cada siguiente esta fachada sur serâ”œÂ¡a objeto de una monumental reforma proyectada por Teodoro Râ”œÂ¡os Balaguer que incluirâ”œÂ¡a una imagen de la Virgen del Pilar en este mismo emplazamiento. Fuente visual: "Aragâ”œâ”‚n: revista grâ”œÃ­fica de cultura aragonesa" (1936).', 1936, 1936, 1936, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65662700, -0.87890500, '0101000020E6100000E44EE960FD1FECBFD655815A0CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/44806382691.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/44806382691.webp', 'https://www.flickr.com/photos/zaragozaantigua/44806382691/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21888, 'Obras del Pilar c.1935', 'Imagen capturada desde la torre de Nuestra Seâ”œâ–’ora del Pilar con una interesante vista de la arboleda de Macanaz y el barrio del Arrabal. Al fondo, la Alcoholera del Pilar y la Uniâ”œâ”‚n Alcoholera Espaâ”œâ–’ola. En primer tâ”œÂ®rmino, obra de reposiciâ”œâ”‚n del tejadillo a dos aguas del remate de la torre noreste del templo, mediante la colocaciâ”œâ”‚n de nuevas vigas de madera que luego serâ”œÃ­n retejadas convenientemente.', 1935, 1935, 1935, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65680800, -0.87852000, '0101000020E6100000B0389CF9D51CECBF26E0D74812D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49670809646.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49670809646.webp', 'https://www.flickr.com/photos/zaragozaantigua/49670809646/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22006, 'Emblema corriente aâ”œâ–’os 40', '"Zaragoza. Pilar de la fe y columna de la patria espaâ”œâ–’ola". Anverso y reverso de un "emblema corriente" de cartâ”œâ”‚n, emitido durante la dâ”œÂ®cada de los cuarenta por Auxilio Social, organizaciâ”œâ”‚n falangista de socorro humanitario y propaganda polâ”œÂ¡tica. Estas insignias, versiâ”œâ”‚n barata de las metâ”œÃ­licas de la Alemania nazi, se entregaban a cambio de donativos obligatorios a la entrada de espectâ”œÃ­culos. Fuente: www.delcampe.net', 1940, 1940, 1949, 'Anos 40', 'CASCO HISTâ”œÃ´RICO', 41.65693300, -0.87869100, '0101000020E6100000E14389963C1EECBFE3546B6116D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36894196236.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36894196236.webp', 'https://www.flickr.com/photos/zaragozaantigua/36894196236/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22034, 'Proyecto Pilar 1948', 'Ilustraciâ”œâ”‚n para el proyecto de construcciâ”œâ”‚n de las dos torres ribereâ”œâ–’as del Pilar, presentado por el arquitecto Miguel â”œÃ¼ngel Navarro Pâ”œÂ®rez en 1948. En 1946, los esposos de la alta sociedad zaragozana Francisco de Borja Urzaiz y Leonor Sala decidieron financiar la construcciâ”œâ”‚n de las dos torres, cuyas primeras piedras se colocaron en 1949, aunque las obras no comenzaron hasta 1951. La del noroeste, llamada de San Francisco de Borja, se finalizâ”œâ”‚ en 1959; la otra, llamada de Santa Leonor, en 1961.', 1948, 1948, 1948, 'Anos 40', 'CASCO HISTâ”œÃ´RICO', 41.65684500, -0.87855200, '0101000020E610000088BB7A15191DECBF43C5387F13D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52526949815.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52526949815.webp', 'https://www.flickr.com/photos/zaragozaantigua/52526949815/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22045, 'El Pilar 1956', 'Imagen de las dos torres en construcciâ”œâ”‚n del Pilar (nombradas de San Francisco de Borja, y de Santa Leonor, como una de las contraprestaciones a sus humanos esponsorizadores, que asâ”œÂ¡ pasaron a la mariana posteridad) y el nuevo Ayuntamiento, tambiâ”œÂ®n en fase de construcciâ”œâ”‚n. La torre de la izquierda fue acabada en 1959, y la de al derecha en 1961. El edificio del Ayuntamiento pareciâ”œâ”‚ afectado por el "mal de las obras del Pilar", pues estuvo mâ”œÃ­s de veinte aâ”œâ–’os en esa tesitura (1946-1965), hasta que finalmente pudo incluirse entre los inconmensurables logros de los "25 aâ”œâ–’os de paz" del Râ”œÂ®gimen. Fuente visual: DARA (AHPZ-DGA). Estudio Coyne.', 1956, 1956, 1956, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65668300, -0.87844600, '0101000020E61000001DAA29C93A1CECBF6A6B44300ED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14791479228.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14791479228.webp', 'https://www.flickr.com/photos/zaragozaantigua/14791479228/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22222, 'El Pilar c.1953', 'Imagen capturada desde la arboleda de Macanaz y centrada en el templo del Pilar durante los preliminares a las obras de recrecimiento de las torres ribereâ”œâ–’as, como indican los muretes perimetrales que circunvalan la oriental torre que serâ”œÃ­ denominada de San Francisco de Borja. A la izquierda, estructura de la nueva Casa Consistorial durante sus prolongadas obras de construcciâ”œâ”‚n. Sobre ella emerge la barroca torre de la Seo. En primer tâ”œÂ®rmino, el râ”œÂ¡o Ebro fluye parsimonioso, parminedeico.', 1953, 1953, 1953, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65700000, -0.87875600, '0101000020E6100000A73D25E7C41EECBF6ABC749318D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48893128741.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48893128741.webp', 'https://www.flickr.com/photos/zaragozaantigua/48893128741/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22225, 'El Pilar c.1950', 'Imagen capturada desde la arboleda de Macanaz y centrada en el templo del Pilar poco antes del definitivo inicio de las obras de recrecimiento de las torres ribereâ”œâ–’as. A la izquierda, esqueleto hormigonado de la nueva Casa Consistorial durante su dilatado proceso de construcciâ”œâ”‚n. En primer tâ”œÂ®rmino, el râ”œÂ¡o Ebro fluye parsimonioso, calmo, regalando la vista del acuâ”œÃ­tico doppelgâ”œÃ±nger pilarista.', 1950, 1950, 1950, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65826000, -0.87929200, '0101000020E6100000444DF4F92823ECBFEA211ADD41D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49123504361.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49123504361.webp', 'https://www.flickr.com/photos/zaragozaantigua/49123504361/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
