INSERT INTO public.photos VALUES (22875, 'Desde el Pilar a San Fernando 1987', 'Luis Mâ”œÂ¡nguez. 1987. Desde la torre de San Francisco de Borja del metropolitano del Pilar, y mediante una interesante fotografâ”œÂ¡a de Luis Mâ”œÂ¡nguez, la visiâ”œâ”‚n de campanario se proyecta hacia el sur de la ciudad del momento, y alcanza elementos urbanos hasta algo mâ”œÃ­s allâ”œÃ­ de los dos kilâ”œâ”‚metros y medio de distancia. De esta forma, llegamos hasta la câ”œâ•‘pula y las traseras de la neoclâ”œÃ­sica iglesia de San Fernando, al fondo, junto al Canal Imperial, y hasta los bloques de la plaza que entonces honraba la memoria del divisionario azul "Muâ”œâ–’oz Grandes" por su lucha contra el bochevismo. Hasta esas alturas canalinas, comenzando por el inmediato Casco Histâ”œâ”‚rico, y sus caracterâ”œÂ¡sticos tejados, la vista asciende por las sucesivas y apreciables terrazas naturales que suben desde el râ”œÂ¡o Ebro, sobre las que se ha configurado y adaptado la plâ”œÃ­stica de un desigual paisaje urbano jalonado de remates, câ”œâ•‘pulas, chimeneas, y elementos referenciales varios que invitan a ir saltando por ellos como si de una versiâ”œâ”‚n local del violinista en el tejado se tratara. Sobre cada uno de ellos, una historia que contar. Algunas son recientes, otras, no tanto, e incluso hay alguna en construcciâ”œâ”‚n. Todas estâ”œÃ­n ahâ”œÂ¡, latentes. Focaliza la imagen la antigua torre de la iglesia parroquial de San Gil Abad, un buen lugar por donde comenzar el relato.', 1987, 1987, 1987, 'Anos 80', 'CASCO HISTâ”œÃ´RICO', 41.65727900, -0.87893800, '0101000020E6100000D2C5A6954220ECBF7EACE0B721D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15845812481.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15845812481.webp', 'https://www.flickr.com/photos/zaragozaantigua/15845812481/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONF