INSERT INTO public.photos VALUES (23186, 'Zaragoza desorden 2000', 'Impactante imagen de avance del proyecto "Zaragoza desorden. The Lost Tapes", que verâ”œÃ­ la luz en la primavera de 2023 con un recopilatorio en forma de doble vinilo y CD ademâ”œÃ­s de un fanzine que rescatarâ”œÃ­n las grabaciones de 31 grupos de mâ”œâ•‘sica punk de la Zaragoza de principios del actual mileno que entonces por distintas circunstancias no pudieron editarse y que ahora, dos dâ”œÂ®cadas despuâ”œÂ®s, sâ”œÂ¡, cuando las circunstancias sociales y polâ”œÂ¡ticas son bastante distintas a las de aquellos aâ”œâ–’os. En la imagen, simpâ”œÃ­tica imaginerâ”œÂ¡a punk sobre un fondo del templo del Pilar del que parece emerger, dios no lo quiera, un hongo nuclear. La Zaragoza antigua y una Zaragoza algo menos antigua.', 2000, 2000, 2000, 'Siglo XXI', 'CASCO HISTâ”œÃ´RICO', 41.65691400, -0.87859500, '0101000020E61000005ABBED42731DECBF6C2409C215D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52525704177.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52525704177.webp', 'https://www.flickr.com/photos/zaragozaantigua/52525704177/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
